Here's a modern MSTest test class for `DataFetcher` covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespondsBeforeTimeout_ReturnsContent()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("fast")
            },
            delay: TimeSpan.FromMilliseconds(100));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken for cooperative timeout
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK),
            delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    /// <summary>Minimal handler that returns a canned response after an optional delay.</summary>
    private sealed class FakeHandler(
        HttpResponseMessage response,
        TimeSpan delay = default) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
                await Task.Delay(delay, cancellationToken);

            return response;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` class | Performance; MSTest best practice |
| Constructor-injected `TestContext` | Enables `readonly`, cleaner than property |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it overruns |
| `Assert.ThrowsExactlyAsync` | Verifies the exact exception type, replaces `[ExpectedException]` |
| `FakeHandler` over mocking library | No external dependency; full control over delay and response |

The `FakeHandler`'s `Task.Delay(delay, cancellationToken)` throws `TaskCanceledException` when the token fires, which is exactly what `HttpClient` does in production — so the cancellation test exercises the real code path.
